<?php
declare(strict_types=1);namespace App\Repositories\ControlEscaneres\Pdo;use App\Repositories\ControlEscaneres\Contracts\ScannerInspectionRepositoryInterface;use App\DTO\ControlEscaneres\{ScannerInspectionCreateData,ScannerInspectionDetailData};use App\Domain\ControlEscaneres\{ScannerInspection,InspectionType};
final class PdoScannerInspectionRepository extends AbstractPdoRepository implements ScannerInspectionRepositoryInterface{private function map(array$r):ScannerInspection{return new ScannerInspection((int)$r['id'],(int)$r['movimiento_id'],new InspectionType($r['tipo']));}public function createInspection(ScannerInspectionCreateData$d):ScannerInspection{$this->stmt('INSERT INTO scanner_inspecciones(movimiento_id,scanner_id,tipo,inspeccionada_at,registrada_por)VALUES(:m,:s,:t,:a,:u)',['m'=>$d->movementId,'s'=>$d->scannerId,'t'=>$d->type->value,'a'=>$d->inspectedAt->format('Y-m-d H:i:s.u'),'u'=>$d->actor->userId]);$x=$this->findByMovementAndType($d->movementId,$d->type);foreach($d->details as$detail)$this->addDetail($x->id,$detail);return$x;}public function addDetail(int$id,ScannerInspectionDetailData$d):void{$this->stmt('INSERT INTO scanner_inspeccion_detalles(inspeccion_id,componente,estado,valor_numerico,valor_texto)VALUES(:i,:c,:e,:n,:t)',['i'=>$id,'c'=>$d->component,'e'=>$d->status,'n'=>$d->numericValue,'t'=>$d->textValue]);}public function findByMovementAndType(int$id,InspectionType$t):?ScannerInspection{$r=$this->stmt('SELECT * FROM scanner_inspecciones WHERE movimiento_id=:i AND tipo=:t',['i'=>$id,'t'=>$t->value])->fetch(\PDO::FETCH_ASSOC);return is_array($r)?$this->map($r):null;}public function listDetails(int$id):array{return$this->stmt('SELECT componente,estado,valor_numerico,valor_texto FROM scanner_inspeccion_detalles WHERE inspeccion_id=:i',['i'=>$id])->fetchAll(\PDO::FETCH_ASSOC);}public function compareDeliveryAndReturn(int$id):array{$a=$this->findByMovementAndType($id,new InspectionType('entrega'));$b=$this->findByMovementAndType($id,new InspectionType('recepcion'));if(!$a||!$b)return[];$rank=['malo'=>0,'regular'=>1,'bueno'=>2,'correcto'=>2,'ok'=>2];$x=[];$left=[];foreach($this->listDetails($a->id)as$r)$left[$r['componente']]=$r;foreach($this->listDetails($b->id)as$r){$old=$left[$r['componente']]??null;if($old===null){$cmp='sin_referencia';}elseif($r['estado']===$old['estado']){$cmp='igual';}else{$before=$rank[strtolower($old['estado'])]??null;$after=$rank[strtolower($r['estado'])]??null;$cmp=$before===null||$after===null?'cambio':($after>$before?'mejoro':'empeoro');}$x[]=['componente'=>$r['componente'],'anterior'=>$old,'posterior'=>$r,'resultado'=>$cmp];}return$x;}}
